framework_css:
:root {
  --color-primary-700: #12366E;
  --color-primary-650: #1B3F78;
  --color-secondary-gold: #B38A4B;
  --color-secondary-muted: #4B5A73;
  --color-accent-purple: #8B4C8F;
  --color-neutral-0: #FFFFFF;
  --color-neutral-50: #F4F6FA;
  --color-neutral-100: #E6EAF0;
  --color-neutral-300: #9AA3B5;
  --color-success: #2E7D32;
  --color-error: #C62828;
  --color-warning: #ED6C02;
  --color-info: #1976D2;

  --font-heading: "Playfair Display", Georgia, serif;
  --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Helvetica Neue", Arial, sans-serif;
  --font-code: "Source Code Pro", SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;

  --font-size-h1: 3rem; /* 48px */
  --font-size-h2: 2rem; /* 32px */
  --font-size-h3: 1.5rem; /* 24px */
  --font-size-body: 1rem; /* 16px */
  --font-size-small: 0.875rem; /* 14px */

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-pill: 9999px;

  --border-subtle: 1px solid var(--color-neutral-100);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-primary-700);
  background-color: var(--color-neutral-50);
}

img {
  max-width: 100%;
  height: auto;
}

a {
  color: var(--color-primary-700);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.container {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  padding-left: var(--space-5);
  padding-right: var(--space-5);
}

/* HEADER */

.site-header {
  position: relative;
  z-index: 10;
  background-color: var(--color-neutral-0);
  border-bottom: var(--border-subtle);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
  min-height: 80px;
}

.site-logo {
  display: inline-flex;
  flex-direction: column;
  justify-content: center;
  color: var(--color-primary-700);
}

.site-logo-primary {
  font-family: var(--font-heading);
  font-size: 1.75rem;
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-tight);
}

.site-logo-secondary {
  margin-top: 2px;
  font-family: var(--font-body);
  font-size: 0.75rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-secondary-muted);
}

.primary-nav {
  margin-left: auto;
}

.primary-nav-list {
  display: flex;
  align-items: center;
  gap: var(--space-4);
  list-style: none;
  margin: 0;
  padding: 0;
}

.primary-nav-link {
  font-size: 0.9375rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-primary-700);
  padding: 4px 0;
}

.primary-nav-link:hover,
.primary-nav-link:focus {
  color: var(--color-primary-650);
  text-decoration: none;
  border-bottom: 2px solid var(--color-secondary-gold);
}

.primary-nav-link.is-active {
  border-bottom: 2px solid var(--color-secondary-gold);
}

.header-menu-pill {
  margin-left: var(--space-4);
  padding: 10px 22px;
  border-radius: var(--radius-pill);
  background-color: var(--color-accent-purple);
  color: var(--color-neutral-0);
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  font-family: var(--font-body);
  font-size: 0.9375rem;
  font-weight: var(--font-weight-medium);
}

.menu-pill-label {
  white-space: nowrap;
}

.menu-pill-icon {
  display: inline-flex;
  flex-direction: column;
  justify-content: center;
  gap: 3px;
}

.menu-pill-bar {
  display: block;
  width: 14px;
  height: 2px;
  border-radius: 999px;
  background-color: var(--color-neutral-0);
}

/* MAIN AREA */

.site-main {
  min-height: 60vh;
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
}

/* FOOTER */

.site-footer {
  background-color: var(--color-neutral-0);
  border-top: var(--border-subtle);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  gap: var(--space-5);
  padding-top: var(--space-6);
  padding-bottom: var(--space-4);
}

.footer-brand {
  max-width: 360px;
}

.footer-logo-primary {
  display: block;
  font-family: var(--font-heading);
  font-size: 1.25rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary-700);
}

.footer-logo-secondary {
  display: block;
  margin-top: 2px;
  font-size: 0.7rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-secondary-muted);
}

.footer-text {
  margin-top: var(--space-3);
  margin-bottom: 0;
  font-size: var(--font-size-small);
  color: var(--color-secondary-muted);
}

.footer-nav {
  flex: 1;
}

.footer-nav-list {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: var(--space-2) var(--space-5);
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-nav-link {
  font-size: var(--font-size-small);
  color: var(--color-primary-700);
}

.footer-nav-link:hover,
.footer-nav-link:focus {
  color: var(--color-primary-650);
  text-decoration: none;
}

.footer-bottom {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-3);
  padding-bottom: var(--space-5);
  border-top: var(--border-subtle);
  font-size: 0.8125rem;
  color: var(--color-secondary-muted);
}

.footer-copy {
  margin: 0;
}

/* RESPONSIVE */

@media (max-width: 900px) {
  .header-inner {
    flex-wrap: wrap;
    row-gap: var(--space-3);
  }

  .primary-nav {
    width: 100%;
    order: 2;
  }

  .primary-nav-list {
    justify-content: flex-start;
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }

  .header-menu-pill {
    order: 1;
  }
}

@media (max-width: 600px) {
  .container {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }

  .site-logo-primary {
    font-size: 1.5rem;
  }

  .footer-inner {
    flex-direction: column;
  }

  .footer-bottom {
    flex-direction: column;
    align-items: flex-start;
    row-gap: var(--space-2);
  }
}
